try {
const item = $input.first().json;
const raw = (item.repository_url || '').trim();

function parse(url) {
  if (!url) return { provider: 'unknown' };
  let href = url;
  if (!/^https?:\/\//i.test(href)) href = 'https://' + href;
  let u;
  try { u = new URL(href); } catch { return { provider: 'unknown' }; }
  const host = u.hostname.replace(/^www\./i, '').toLowerCase();
  const path = u.pathname.replace(/^\//, '').replace(/\.git$/, '').replace(/\/$/, '');
  if (host === 'github.com') {
    const [owner, repo] = path.split('/');
    if (!owner || !repo) return { provider: 'unknown' };
    return { provider: 'github', owner, repo };
  }
  if (host === 'gitlab.com' || host.endsWith('.gitlab.com')) {
    if (!path) return { provider: 'unknown' };
    return { provider: 'gitlab', projectPath: path, encoded: encodeURIComponent(path) };
  }
  return { provider: 'unknown' };
}

return [{ json: { ...item, repo_info: parse(raw) } }];
} catch (err) {
  const errMsg = err && err.message ? err.message : String(err);
  // Fallback shape so downstream nodes can proceed.
  // Stage: parse-repo-1
  return [{ json: { ...$input.first().json, repo_info: { provider: "unknown" }, _node_error: errMsg } }];
}

try {
const repoPkg = $input.first().json;
const payload = $('Parse Repo URL').item.json;
const info = payload.package_info || null;
const kind = payload.submission_kind || 'package';

const repoValid = repoPkg && typeof repoPkg === 'object' && !Array.isArray(repoPkg) && !repoPkg.error && Object.keys(repoPkg).length > 0;
const pkgAvailable = !!(info && info.available);

// Dependencies source: published package first, repo fallback.
const pkgDeps = pkgAvailable ? { ...(info.dependencies || {}), ...(info.peerDependencies || {}) } : {};
const repoDeps = repoValid ? { ...(repoPkg.dependencies || {}), ...(repoPkg.peerDependencies || {}) } : {};
const depsSource = pkgAvailable ? 'registry' : (repoValid ? 'repo' : 'none');
const deps = depsSource === 'registry' ? pkgDeps : (depsSource === 'repo' ? repoDeps : {});

// OSV ecosystem tag from the pre-detected registry, default to npm.
const ecosystem = info?.ecosystem || 'npm';

function cleanVersion(raw) {
  if (typeof raw !== 'string') return null;
  const match = raw.match(/\d+\.\d+\.\d+/);
  return match ? match[0] : null;
}

const queries = Object.entries(deps)
  .map(([name, version]) => {
    const v = cleanVersion(version);
    if (!v) return null;
    return { package: { name, ecosystem }, version: v };
  })
  .filter(Boolean)
  .slice(0, 100);

// Cross-check published vs repo (only when BOTH are present).
const mismatches = [];
if (pkgAvailable && repoValid) {
  ['preinstall', 'install', 'postinstall'].forEach((k) => {
    const pkgVal = info.scripts?.[k] || null;
    const repoVal = repoPkg.scripts?.[k] || null;
    if (pkgVal !== repoVal) {
      mismatches.push({ kind: 'install_script_divergence', script: k, published: pkgVal, repo: repoVal });
    }
  });
  const pkgSet = new Set(Object.keys(pkgDeps));
  const repoSet = new Set(Object.keys(repoDeps));
  const onlyInPkg = [...pkgSet].filter((n) => !repoSet.has(n));
  const onlyInRepo = [...repoSet].filter((n) => !pkgSet.has(n));
  if (onlyInPkg.length > 0) mismatches.push({ kind: 'deps_only_in_published', names: onlyInPkg.slice(0, 20) });
  if (onlyInRepo.length > 0) mismatches.push({ kind: 'deps_only_in_repo', names: onlyInRepo.slice(0, 20) });
  const submitted = (payload.repository_url || '').toLowerCase();
  const declared = (info.declaredRepository || '').toLowerCase();
  const owner = payload.repo_info?.owner?.toLowerCase();
  if (declared && submitted && owner && !declared.includes(owner)) {
    mismatches.push({ kind: 'declared_repo_vs_submitted', submitted, declared });
  }
}

const hasInstallScripts = pkgAvailable && Object.keys(info.installScripts || {}).length > 0;

return [{
  json: {
    queries,
    _skipped: queries.length === 0,
    _reason: queries.length === 0 ? `No dependencies to scan (source: ${depsSource}).` : null,
    ecosystem,
    depsSource,
    kind,
    hasInstallScripts,
    install_scripts: pkgAvailable ? info.installScripts || {} : {},
    mismatches,
    registry_available: pkgAvailable,
    not_implemented: info?.notImplemented === true,
    registry: info?.registry || null,
    packageName: info?.packageName || null,
    version: info?.version || null,
    dist: info?.dist || null,
  },
}];
} catch (err) {
  const errMsg = err && err.message ? err.message : String(err);
  // Fallback shape so downstream nodes can proceed.
  // Stage: osv-build-1
  return [{ json: { queries: [], _skipped: true, _reason: "Build Package Scan Data threw: " + errMsg, ecosystem: "npm", depsSource: "none", kind: null, hasInstallScripts: false, install_scripts: {}, mismatches: [], registry_available: false, not_implemented: false, registry: null, packageName: null, version: null, dist: null, _node_error: errMsg } }];
}

try {
const osv = $input.first().json || {};
const batch = $('Build Package Scan Data').item.json;
const results = Array.isArray(osv.results) ? osv.results : [];

const common = {
  runAt: new Date().toISOString(),
  deps_source: batch.depsSource,
  ecosystem: batch.ecosystem,
  registry: batch.registry,
  registry_available: batch.registry_available,
  not_implemented: batch.not_implemented,
  package_name: batch.packageName,
  version: batch.version,
  dist: batch.dist,
  install_scripts: batch.install_scripts,
  has_install_scripts: batch.hasInstallScripts,
  cross_check_mismatches: batch.mismatches,
};

if (batch._skipped) {
  return [{
    json: {
      stage: 'dependencies',
      result: {
        ...common,
        skipped: true,
        message: batch._reason || 'No dependencies to scan.',
      },
    },
  }];
}

const vulnerable = [];
results.forEach((r, idx) => {
  if (r && Array.isArray(r.vulns) && r.vulns.length > 0) {
    const q = batch.queries[idx];
    vulnerable.push({
      package: q.package.name,
      version: q.version,
      vulnIds: r.vulns.map((v) => v.id),
    });
  }
});

const passed = vulnerable.length === 0 && !batch.hasInstallScripts && batch.mismatches.length === 0;

return [{
  json: {
    stage: 'dependencies',
    result: {
      ...common,
      scanned: batch.queries.length,
      vulnerable_count: vulnerable.length,
      vulnerable,
      passed,
    },
  },
}];
} catch (err) {
  const errMsg = err && err.message ? err.message : String(err);
  // Fallback shape so downstream nodes can proceed.
  // Stage: deps-format-1
  return [{ json: { stage: "dependencies", result: { runAt: new Date().toISOString(), error: errMsg, passed: false, skipped: true, message: "Format Package Scan Result threw: " + errMsg } } }];
}

try {
const payload = $input.first().json;
const info = payload.package_info || null;
const repo = payload.repo_info || {};

const ALLOW_EXT = /\.(js|ts|mjs|cjs|jsx|tsx)$/;
const SKIP_PATTERNS = [/node_modules/, /\.git/, /(^|\/)test[s]?\//, /\.test\./, /\.spec\./, /\.d\.ts$/, /\.min\.(js|css)$/, /\.map$/, /(^|\/)examples?\//, /(^|\/)docs?\//, /(^|\/)fixtures?\//];
const PER_FILE_CAP = 10000;
const TOTAL_BUDGET = 100000;
const MAX_FILES = 20;

function keepPath(path) {
  if (!ALLOW_EXT.test(path)) return false;
  return !SKIP_PATTERNS.some((r) => r.test(path));
}

function escRe(s) {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

async function loadNpmTree(name, version) {
  try {
    const res = await fetch(`https://data.jsdelivr.com/v1/package/npm/${encodeURIComponent(name)}@${encodeURIComponent(version)}`);
    if (!res.ok) return null;
    const tree = await res.json();
    const files = [];
    function walk(node, prefix) {
      if (node.type === 'file') {
        const full = prefix + '/' + node.name;
        if (keepPath(full)) files.push({ path: full, size: node.size || 0 });
      } else if (Array.isArray(node.files)) {
        node.files.forEach((c) => walk(c, prefix + '/' + node.name));
      }
    }
    if (Array.isArray(tree.files)) tree.files.forEach((f) => walk(f, ''));
    return {
      source: 'npm:jsdelivr',
      files,
      fetchUrl: (p) => `https://cdn.jsdelivr.net/npm/${encodeURIComponent(name)}@${encodeURIComponent(version)}${p}`,
    };
  } catch {
    return null;
  }
}

async function loadGitHubTree(owner, repoName) {
  try {
    const res = await fetch(`https://api.github.com/repos/${owner}/${repoName}/git/trees/HEAD?recursive=1`, {
      headers: { Accept: 'application/vnd.github+json' },
    });
    if (!res.ok) return null;
    const tree = await res.json();
    const files = (tree.tree || [])
      .filter((n) => n.type === 'blob')
      .map((n) => ({ path: '/' + n.path, size: n.size || 0 }))
      .filter((f) => keepPath(f.path));
    return {
      source: 'github:raw',
      files,
      fetchUrl: (p) => `https://raw.githubusercontent.com/${owner}/${repoName}/HEAD${p}`,
    };
  } catch {
    return null;
  }
}

let scanner = null;
if (info?.available && info.registry === 'npm') {
  scanner = await loadNpmTree(info.packageName, info.version);
}
if (!scanner && repo.provider === 'github') {
  scanner = await loadGitHubTree(repo.owner, repo.repo);
}

if (!scanner) {
  return [{ json: { ...payload, package_code: null, files_scanned: 0, files_available: 0, bytes_scanned: 0, scan_source: null } }];
}

// Prioritisation: install scripts, main entry, bin/, common entry names, src/, then small files.
const priorityRegex = [];
Object.values(info?.installScripts || {}).forEach((s) => {
  const m = typeof s === 'string' ? s.match(/\S+\.(?:js|ts|mjs|cjs)/) : null;
  if (m) priorityRegex.push(new RegExp(escRe(m[0]) + '$'));
});
priorityRegex.push(/\/bin\//);
priorityRegex.push(/^\/(index|main|entry|cli)\.(js|ts|mjs|cjs)$/);
priorityRegex.push(/^\/src\//);

function priority(p) {
  for (let i = 0; i < priorityRegex.length; i++) if (priorityRegex[i].test(p)) return i;
  return 999;
}

scanner.files.sort((a, b) => priority(a.path) - priority(b.path) || a.size - b.size);
const candidates = scanner.files.slice(0, MAX_FILES);

const contents = await Promise.all(candidates.map(async (f) => {
  try {
    const res = await fetch(scanner.fetchUrl(f.path));
    if (!res.ok) return null;
    const text = await res.text();
    return { path: f.path, body: text.slice(0, PER_FILE_CAP), bytes: Math.min(text.length, PER_FILE_CAP) };
  } catch {
    return null;
  }
}));

const included = [];
let used = 0;
for (const c of contents) {
  if (!c) continue;
  if (used + c.bytes > TOTAL_BUDGET) break;
  included.push(c);
  used += c.bytes;
}

const code = included.map((c) => `// ==== ${c.path} (${c.bytes} bytes) ====\n${c.body}`).join('\n\n');

return [{
  json: {
    ...payload,
    package_code: code || null,
    files_scanned: included.length,
    files_available: scanner.files.length,
    bytes_scanned: used,
    scan_source: scanner.source,
  },
}];
} catch (err) {
  const errMsg = err && err.message ? err.message : String(err);
  // Fallback shape so downstream nodes can proceed.
  // Stage: fetch-code-1
  return [{ json: { ...$input.first().json, package_code: null, files_scanned: 0, files_available: 0, bytes_scanned: 0, scan_source: null, _node_error: errMsg } }];
}

