try {
const res = $input.first().json || {};
const fetchCodeOut = $('Fetch Package Code').item.json;
const text = res?.content?.[0]?.text || '';
let parsed = null;
let parseError = null;
try {
  const match = text.match(/\{[\s\S]*\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch (err) {
  parseError = err.message;
}

return [{
  json: {
    stage: 'ai_analysis',
    result: {
      runAt: new Date().toISOString(),
      model: 'claude-haiku-4-5',
      raw_text: text,
      parsed,
      parse_error: parseError,
      usage: res?.usage || null,
      files_scanned: fetchCodeOut?.files_scanned ?? 0,
      files_available: fetchCodeOut?.files_available ?? 0,
      bytes_scanned: fetchCodeOut?.bytes_scanned ?? 0,
      scan_source: fetchCodeOut?.scan_source || null,
    },
  },
}];
} catch (err) {
  const errMsg = err && err.message ? err.message : String(err);
  // Fallback shape so downstream nodes can proceed.
  // Stage: ai-format-1
  return [{ json: { stage: "ai_analysis", result: { runAt: new Date().toISOString(), error: errMsg, parsed: null, parse_error: errMsg, model: "claude-haiku-4-5", raw_text: null } } }];
}

try {
const merged = $input.first().json;

function pick(stageName) {
  const stages = Array.isArray(merged.stage) ? merged.stage : [merged.stage];
  const results = Array.isArray(merged.result) ? merged.result : [merged.result];
  for (let i = 0; i < stages.length; i++) {
    if (stages[i] === stageName) return results[i];
  }
  return null;
}

const depsR = pick('dependencies');
const aiR = pick('ai_analysis');

function stagePassed(r) {
  if (!r) return null;
  if (r.skipped) return null;
  if (typeof r.passed === 'boolean') return r.passed;
  return null;
}

const summary = {
  runAt: new Date().toISOString(),
  dependencies_passed: stagePassed(depsR),
  ai_risk_level: aiR?.parsed?.risk_level ?? null,
  ai_recommendation: aiR?.parsed?.recommendation ?? null,
  ai_files_scanned: aiR?.files_scanned ?? null,
  ai_files_available: aiR?.files_available ?? null,
  ai_scan_source: aiR?.scan_source ?? null,
  ai_bytes_scanned: aiR?.bytes_scanned ?? null,
  vulnerable_dep_count: depsR?.vulnerable_count ?? null,
  ai_concern_count: Array.isArray(aiR?.parsed?.concerns) ? aiR.parsed.concerns.length : null,
  registry: depsR?.registry ?? null,
  registry_available: depsR?.registry_available ?? null,
  not_implemented: depsR?.not_implemented ?? null,
  package_name: depsR?.package_name ?? null,
  version: depsR?.version ?? null,
  has_install_scripts: depsR?.has_install_scripts ?? null,
  install_scripts: depsR?.install_scripts ?? null,
  cross_check_mismatch_count: Array.isArray(depsR?.cross_check_mismatches) ? depsR.cross_check_mismatches.length : null,
};

return [{ json: { stage: 'summary', result: summary, status: 'completed' } }];
} catch (err) {
  const errMsg = err && err.message ? err.message : String(err);
  // Fallback shape so downstream nodes can proceed.
  // Stage: summary-1
  return [{ json: { stage: "summary", result: { runAt: new Date().toISOString(), error: errMsg, passed: false }, status: "failed" } }];
}
